"""
Secure Advanced Data Filtering Service for MongoDB.

Uses MongoDB's built-in query operators instead of $where to avoid
server-side JavaScript injection vulnerabilities.
"""

from pymongo import MongoClient
from pymongo.errors import PyMongoError
import re
from typing import Any


# Whitelist of allowed operators and fields
ALLOWED_OPERATORS = {
    "eq", "ne", "gt", "gte", "lt", "lte",
    "in", "nin", "exists", "regex", "type",
    "and", "or", "not", "nor",
    "size", "all", "elemMatch",
}

ALLOWED_FIELDS = {
    "name", "age", "email", "status", "created_at",
    "category", "price", "quantity", "tags", "rating",
    "city", "country", "department", "score",
}


class SecureFilterBuilder:
    """
    Translates user-friendly filter expressions into safe MongoDB queries.
    
    Instead of accepting raw JavaScript (which is vulnerable to injection),
    this accepts structured filter definitions and builds MongoDB queries
    using native query operators.
    """

    def __init__(self, allowed_fields: set[str] = None, allowed_operators: set[str] = None):
        self.allowed_fields = allowed_fields or ALLOWED_FIELDS
        self.allowed_operators = allowed_operators or ALLOWED_OPERATORS

    def validate_field(self, field: str) -> bool:
        """Validate that a field name is in the whitelist."""
        base_field = field.split(".")[0]
        if base_field not in self.allowed_fields:
            raise ValueError(
                f"Field '{field}' is not allowed. Allowed fields: {sorted(self.allowed_fields)}"
            )
        return True

    def validate_operator(self, operator: str) -> bool:
        """Validate that an operator is in the whitelist."""
        op = operator.lstrip("$")
        if op not in self.allowed_operators:
            raise ValueError(
                f"Operator '${op}' is not allowed. Allowed operators: {sorted(self.allowed_operators)}"
            )
        return True

    def validate_value(self, value: Any) -> Any:
        """
        Sanitize and validate filter values.
        Prevents injection through specially crafted values.
        """
        if isinstance(value, dict):
            # Check for operator injection in values
            for key in value:
                if key.startswith("$"):
                    if key == "$regex":
                        # Sanitize regex to prevent ReDoS
                        pattern = value[key]
                        if len(str(pattern)) > 200:
                            raise ValueError("Regex pattern too long (max 200 chars)")
                    self.validate_operator(key)
            return {k: self.validate_value(v) for k, v in value.items()}
        elif isinstance(value, list):
            return [self.validate_value(item) for item in value]
        elif isinstance(value, (str, int, float, bool, type(None))):
            return value
        else:
            raise ValueError(f"Unsupported value type: {type(value).__name__}")

    def build_condition(self, field: str, operator: str, value: Any) -> dict:
        """Build a single filter condition safely."""
        self.validate_field(field)
        self.validate_operator(operator)
        safe_value = self.validate_value(value)

        op = operator if operator.startswith("$") else f"${operator}"
        return {field: {op: safe_value}}

    def build_query(self, filter_definition: dict | list) -> dict:
        """
        Build a complete MongoDB query from a structured filter definition.

        Accepts structured input like:
        {
            "conditions": [
                {"field": "age", "op": "gte", "value": 18},
                {"field": "status", "op": "eq", "value": "active"},
                {"field": "score", "op": "gt", "value": 85}
            ],
            "logic": "and"
        }
        """
        if isinstance(filter_definition, dict) and "conditions" in filter_definition:
            conditions = []
            for cond in filter_definition["conditions"]:
                if "conditions" in cond:
                    # Nested logical group
                    nested = self.build_query(cond)
                    conditions.append(nested)
                else:
                    field = cond.get("field")
                    operator = cond.get("op", "eq")
                    value = cond.get("value")

                    if field is None:
                        raise ValueError("Each condition must have a 'field'")

                    condition = self.build_condition(field, operator, value)
                    conditions.append(condition)

            logic = filter_definition.get("logic", "and")
            if logic not in ("and", "or", "nor"):
                raise ValueError(f"Invalid logic operator: {logic}")

            if len(conditions) == 1 and logic == "and":
                return conditions[0]
            return {f"${logic}": conditions}

        raise ValueError(
            "Filter definition must be a dict with 'conditions' key"
        )


class MongoFilterService:
    """
    Advanced Data Filtering Service using secure MongoDB queries.
    
    This service provides complex filtering capabilities WITHOUT
    using $where or server-side JavaScript, avoiding injection attacks.
    """

    def __init__(self, connection_string: str = "mongodb://localhost:27017",
                 database_name: str = "filter_service_db"):
        self.client = MongoClient(connection_string, serverSelectionTimeoutMS=5000)
        self.db = self.client[database_name]
        self.filter_builder = SecureFilterBuilder()

    def close(self):
        """Close the MongoDB connection."""
        self.client.close()

    def query_collection(self, collection_name: str, filter_definition: dict,
                         projection: dict = None, sort: list = None,
                         limit: int = 100, skip: int = 0) -> list[dict]:
        """
        Execute a safe, validated query on a collection.

        Args:
            collection_name: Name of the MongoDB collection
            filter_definition: Structured filter (see SecureFilterBuilder.build_query)
            projection: Fields to include/exclude
            sort: List of (field, direction) tuples
            limit: Maximum documents to return (capped at 1000)
            skip: Number of documents to skip

        Returns:
            List of matching documents
        """
        # Validate collection name (alphanumeric + underscore only)
        if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', collection_name):
            raise ValueError(f"Invalid collection name: {collection_name}")

        # Cap the limit to prevent excessive data retrieval
        limit = min(max(1, limit), 1000)
        skip = max(0, skip)

        # Build the safe query
        query = self.filter_builder.build_query(filter_definition)

        # Validate projection fields
        safe_projection = None
        if projection:
            safe_projection = {}
            for field, include in projection.items():
                self.filter_builder.validate_field(field)
                safe_projection[field] = 1 if include else 0

        # Validate sort fields
        safe_sort = None
        if sort:
            safe_sort = []
            for field, direction in sort:
                self.filter_builder.validate_field(field)
                if direction not in (1, -1):
                    raise ValueError(f"Sort direction must be 1 or -1, got {direction}")
                safe_sort.append((field, direction))

        # Execute query
        collection = self.db[collection_name]
        cursor = collection.find(query, safe_projection)

        if safe_sort:
            cursor = cursor.sort(safe_sort)
        cursor = cursor.skip(skip).limit(limit)

        results = list(cursor)

        # Convert ObjectId to string for JSON serialization
        for doc in results:
            if "_id" in doc:
                doc["_id"] = str(doc["_id"])

        return results

    def count_documents(self, collection_name: str, filter_definition: dict) -> int:
        """Count documents matching the filter."""
        if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', collection_name):
            raise ValueError(f"Invalid collection name: {collection_name}")

        query = self.filter_builder.build_query(filter_definition)
        return self.db[collection_name].count_documents(query)

    def aggregate_query(self, collection_name: str, filter_definition: dict,
                        group_by: str, aggregations: dict) -> list[dict]:
        """
        Perform aggregation with safe filtering.

        Args:
            collection_name: Collection name
            filter_definition: Filter conditions
            group_by: Field to group by
            aggregations: Dict of {output_field: {"op": "sum|avg|min|max|count", "field": "source_field"}}
        """
        if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', collection_name):
            raise ValueError(f"Invalid collection name: {collection_name}")

        ALLOWED_AGG_OPS = {"sum", "avg", "min", "max", "count", "first", "last"}

        query = self.filter_builder.build_query(filter_definition)
        self.filter_builder.validate_field(group_by)

        group_stage = {"_id": f"${group_by}"}
        for output_field, agg_def in aggregations.items():
            # Validate output field name
            if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', output_field):
                raise ValueError(f"Invalid output field name: {output_field}")

            op = agg_def.get("op", "sum")
            if op not in ALLOWED_AGG_OPS:
                raise ValueError(f"Unsupported aggregation: {op}")

            source_field = agg_def.get("field")
            if source_field:
                self.filter_builder.validate_field(source_field)

            if op == "count":
                group_stage[output_field] = {"$sum": 1}
            else:
                group_stage[output_field] = {f"${op}": f"${source_field}"}

        pipeline = [
            {"$match": query},
            {"$group": group_stage},
            {"$sort": {"_id": 1}},
            {"$limit": 100},
        ]

        results = list(self.db[collection_name].aggregate(pipeline))
        for doc in results:
            if "_id" in doc and hasattr(doc["_id"], "__str__"):
                doc["group"] = str(doc["_id"])
                del doc["_id"]
        return results


